mapper.insert:
INSERT  INTO TB_LOGIN_LOG
      ( LOG_ID
      , CONECT_MTHD
      , CONECT_ID
      , CONECT_IP
      , ERROR_OCCRRNC_AT
      , ERROR_CODE
      , CREAT_DT )
VALUES  ( #{logId}
        , #{loginMthd}
        , #{loginId}
        , #{loginIp}
        , #{errOccrrAt}
        , #{errorCode}
        , NOW()::TIMESTAMP(0) )

mapper.select:
SELECT A.LOG_ID , TO_CHAR(A.CREAT_DT, 'YYYY-MM-DD HH24:MI') CREAT_DT , A.CONECT_MTHD , A.CONECT_IP , A.CONECT_ID , B.USER_NM AS LOGIN_NM FROM TB_LOGIN_LOG A LEFT OUTER JOIN VW_USER_MASTER B ON A.CONECT_ID = B.ESNTL_ID WHERE 1 = 1
AND A.CONECT_MTHD LIKE '%' || #{searchWrd} || '%'
AND TO_CHAR(A.CREAT_DT, 'YYYYMMDD') BETWEEN #{searchBgnDe} AND #{searchEndDe}
ORDER BY A.CREAT_DT DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(A.LOG_ID) AS cnt FROM TB_LOGIN_LOG A LEFT OUTER JOIN VW_USER_MASTER B ON A.CONECT_ID = B.ESNTL_ID WHERE 1 = 1
AND A.CONECT_MTHD LIKE '%' || #{searchWrd} || '%'
AND TO_CHAR(A.CREAT_DT, 'YYYYMMDD') BETWEEN #{searchBgnDe} AND #{searchEndDe}
